Exit fullscreen mode

What’s wrong?

• The token lives 7 days → huge replay window.

• The client gets the token in JSON → most devs stash it in localStorage, open to XSS.

• The secret is a static string; no rotation, no algorithm flexibility.

2️⃣ The layered version (the victory)

// server-secure.js
require('dotenv').config(); // keep SECRET out of source
const express = require('express');
const jwt = require('jsonwebtoken');
const redis = require('redis'); // for refresh‑token revocation/rotation
const app = express();
app.use(express.json());
const ACCESS_TOKEN_SECRET = process.env.ACCESS_TOKEN_SECRET; // strong random
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET; // another strong random
const redisClient = redis.createClient(); // assumes Redis running locally
// Helper: generate a short‑lived access token (5 min)
function signAccessToken(payload) {
return jwt.sign(payload, ACCESS_TOKEN_SECRET, { expiresIn: '5m' });
}
// Helper: generate a refresh token (30 days) and store its jti in Redis
async function signRefreshToken(payload) {
const jti = jwt.sign({}, REFRESH_TOKEN_SECRET, { expiresIn: '30d' }); // random jti
await redisClient.set(jti, JSON.stringify(payload), 'EX', 30 * 24 * 60 * 60); // 30 days TTL
return jti;
}
// ---------- Login (OAuth‑style password grant for demo) ----------
app.post('/login', async (req, res) => {
const { username, password } = req.body;
// In real life, verify against DB + hash; here we just fake it
if (username !== 'admin' || password !== 'password') {
return res.status(401).send('Invalid credentials');
}
const accessPayload = { sub: username, role: 'user' };
const refreshPayload = { sub: username };
const accessToken = signAccessToken(accessPayload);
const refreshTokenJti = await signRefreshToken(refreshPayload);
// 🍪 Set refresh token as httpOnly cookie
res.cookie('refreshToken', refreshTokenJti, {
httpOnly: true,
secure: true, // HTTPS only in prod
sameSite: 'strict',
maxAge: 30 * 24 * 60 * 60 * 1000, // 30 days
});
// Access token sent in body – client keeps it in memory (e.g., Redux state)
res.json({ accessToken });
});
// ---------- Token refresh endpoint ----------
app.post('/token', async (req, res) => {
const refreshTokenJti = req.cookies.refreshToken;
if (!refreshTokenJti) return res.status(401).send('No refresh token');
const stored = await redisClient.get(refreshTokenJti);
if (!stored) return res.status(401).send('Refresh token expired or revoked');
const payload = JSON.parse(stored);
// Optional: rotate refresh token (delete old, issue new)
await redisClient.del(refreshTokenJti);
const newRefreshJti = await signRefreshToken(payload);
res.cookie('refreshToken', newRefreshJti, {
httpOnly: true,
secure: true,
sameSite: 'strict',
maxAge: 30 * 24 * 60 * 60 * 1000,
});
const newAccess = signAccessToken({ sub: payload.sub, role: payload.role });
res.json({ accessToken: newAccess });
});
// ---------- Protected route ----------
app.get('/api/data', (req, res) => {
const auth = req.headers.authorization;
if (!auth) return res.status(401).send('Missing token');
const token = auth.split(' ')[1];
try {
const payload = jwt.verify(token, ACCESS_TOKEN_SECRET);
res.json({ msg: `Hello ${payload.sub}`, payload });
} catch (e) {
res.status(401).send('Invalid or expired access token');
}
});
// ---------- Logout (revoke refresh token) ----------
app.post('/logout', async (req, res) => {
const refreshTokenJti = req.cookies.refreshToken;
if (refreshTokenJti) await redisClient.del(refreshTokenJti);
res.clearCookie('refreshToken', { httpOnly: true, secure: true, sameSite: 'strict' });
res.send('Logged out');
});
(async () => {
await redisClient.connect();
app.listen(3000, () => console.log('Secure server on :3000'));
})();

